          {/* Job Title and Description - centered between CTA and bottom */}
          {(() => {
            const title = jobTitleLimited || "";

            // Function to split text into lines with max chars per line
            const splitIntoLines = (text, maxChars) => {
              const words = text.split(" ");
              const lines = [];
              let currentLine = "";
              words.forEach((word) => {
                const testLine = currentLine ? `${currentLine} ${word}` : word;
                if (testLine.length > maxChars && currentLine) {
                  lines.push(currentLine);
                  currentLine = word;
                } else {
                  currentLine = testLine;
                }
              });
              if (currentLine) lines.push(currentLine);
              return lines;
            };

            // Try different font sizes until we fit in max 2 lines
            let fontSize = 84;
            let charsPerLine = 18; // chars per line at 84px
            let lines = splitIntoLines(title, charsPerLine);

            // Reduce font size if more than 2 lines
            while (lines.length > 2 && fontSize > 48) {
              fontSize -= 8;
              charsPerLine = Math.floor(18 * (84 / fontSize)); // more chars per line with smaller font
              lines = splitIntoLines(title, charsPerLine);
            }

            // If still more than 2 lines, force truncate to 2
            if (lines.length > 2) {
              lines = lines.slice(0, 2);
              lines[1] = lines[1].slice(0, -3) + "...";
            }

            // Layout constants
            const ctaBottom = 1020; // Bottom of CTA button
            const descriptionY = 1300; // Fixed position for description
            const lineHeight = fontSize * 1.1; // Line height relative to font size

            // Calculate center point between CTA and description
            const centerY = ctaBottom + (descriptionY - ctaBottom - 60) / 2;

            // For proper centering: single line at centerY, two lines split above/below
            let firstLineY;
            if (lines.length === 1) {
              firstLineY = centerY; // Single line exactly at center
            } else {
              firstLineY = centerY - (lineHeight / 2); // Two lines: first above center
            }

            return (
              <>
                <text
                  x="540"
                  y={firstLineY}
                  textAnchor="middle"
                  dominantBaseline="middle"
                  style={{
                    fontFamily: "Inter, sans-serif",
                    fontSize: `${fontSize}px`,
                    fontWeight: 800,
                    fill: "#FFFFFF",
                    letterSpacing: "-2px",
                  }}
                >
                  {lines.map((line, i) => (
                    <tspan key={i} x="540" dy={i === 0 ? 0 : lineHeight}>
                      {line}
                    </tspan>
                  ))}
                </text>
                {/* Link Description - fixed position */}
                {linkDescription && (
                  <text
                    x="540"
                    y={descriptionY}
                    textAnchor="middle"
                    dominantBaseline="middle"
                    style={{
                      fontFamily: "Inter, sans-serif",
                      fontSize: "42px",
                      fontWeight: 500,
                      fill: subtitleColor,
                    }}
                  >
                    {linkDescription}
                  </text>
                )}
              </>
            );
          })()}
